using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Build IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, apiKey)
    .AsIChatClient();

// --- Tools ---
var notebook = new ResearchNotebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        WebSearchTool.SearchAsync, "SearchWeb",
        "Searches the web for information on a given query and returns relevant results."),
    AIFunctionFactory.Create(
        notebook.TakeNote, "TakeNote",
        "Saves a research note with a title and content. Use this to record key findings."),
    AIFunctionFactory.Create(
        notebook.GetNotes, "GetNotes",
        "Retrieves all research notes taken so far. Use before writing the final summary."),
};

// --- Build agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research the given topic.

        Follow this process:
        1. Break the topic into 3-5 key subtopics or questions.
        2. Use SearchWeb to find information about each subtopic.
        3. Use TakeNote to record important findings with clear titles.
        4. After gathering enough information (at least 3 notes), use GetNotes to review.
        5. Provide a comprehensive, well-structured summary of your findings.

        Be thorough but focused. Always cite which searches informed each note.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes.",
    tools: tools);

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// --- Run agent with streaming output ---
var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine("\n--- Research Notes ---");

foreach (var (title, content) in notebook.Notes)
{
    Console.WriteLine($"\n## {title}");
    Console.WriteLine(content);
}

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Stores research notes collected by the agent during its investigation.</summary>
public sealed class ResearchNotebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public IReadOnlyList<(string Title, string Content)> Notes => _notes;

    public string TakeNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note with key findings")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: '{title}'";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

/// <summary>Searches the web using the Wikipedia API as a free, keyless source.</summary>
public static class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static async Task<string> SearchAsync(
        [Description("The search query to look up")] string query)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search"
                    + $"&srsearch={encoded}&format=json&srlimit=5&srprop=snippet";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            using var response = await s_httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync();
            var doc = JsonDocument.Parse(json);
            var results = doc.RootElement.GetProperty("query").GetProperty("search");

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}\n");

            foreach (var result in results.EnumerateArray())
            {
                var title = result.GetProperty("title").GetString();
                var snippet = result.GetProperty("snippet").GetString()
                    ?.Replace("<span class=\"searchmatch\">", "")
                    .Replace("</span>", "")
                    .Replace("&quot;", "\"")
                    .Replace("&amp;", "&");
                sb.AppendLine($"- {title}: {snippet}");
            }

            return sb.Length > 0 ? sb.ToString() : "No results found.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

