    instructions: """
        You are a research agent. Your job is to thoroughly research the given topic.

        Follow this process:
        1. Break the topic into 3-5 key subtopics or questions.
        2. Use SearchWeb to find information about each subtopic.
        3. Use TakeNote to record important findings with clear titles.
        4. After gathering enough information (at least 3 notes), use GetNotes to review.
        5. Provide a comprehensive, well-structured summary of your findings.

        Be thorough but focused. Always cite which searches informed each note.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes.",
    tools: tools);

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

